onClick:
{{
Promise.all([

    ObtenerNCImpresion.run(),

    ObtenerFactAfectadaNCImpresion.run()

])

.then(async () => {

    await storeValue(
        "ncImpresion",
        ObtenerNCImpresion.data[0]
    );

    await storeValue(
        "fcAfectadaNCImpresion",
        ObtenerFactAfectadaNCImpresion.data
    );

    download(

        JS_ImpresionNC.generarHTMLNC(),

        ObtenerNCImpresion.data[0]
            .numero_nota_credito
        +
        ".html",

        "text/html"

    );

    showAlert(
        "Nota de crédito descargada correctamente",
        "success"
    );

});
}}

tooltip:
{{
!tblConsultaNC.selectedRow?.id_nota_credito
?
"Debe seleccionar una nota de crédito en la tabla"
:
""
}}
